template='''import{{useState,useEffect}}from"react";import{{useNavigate}}from"react-router-dom";import Navbar from"../components/Navbar";import BackButton from"../components/BackButton";import"./GamifiedLearning.css";export default function {name}(){{const navigate=useNavigate();const[currentCheckpoint,setCurrentCheckpoint]=useState(0);const[completedCheckpoints,setCompletedCheckpoints]=useState([]);const[quizAnswers,setQuizAnswers]=useState({{}});const[score,setScore]=useState(0);const[moduleComplete,setModuleComplete]=useState(false);const[quizResult,setQuizResult]=useState(null);const checkpoints=[{{id:0,type:"intro",title:"Introduction to {title}",content:"{title} requires preparation. Learn essential safety measures!",icon:"{icon}"}},{{id:1,type:"video",title:"Watch: {title}",videoUrl:"{video}",icon:"📹"}},{{id:2,type:"content",title:"Before Emergency",content:{before},icon:"⚠️"}},{{id:3,type:"quiz",title:"Checkpoint Quiz: Preparation",questions:[{{question:"What is most important in preparation?",options:["Ignore it","Have a plan and supplies","Do nothing","Wait"],correct:1}},{{question:"Should you learn about this hazard?",options:["No","Yes, knowledge saves lives","Maybe","Never"],correct:1}},{{question:"Is an emergency kit needed?",options:["No","Yes, essential","Only sometimes","Never"],correct:1}},{{question:"Should you practice drills?",options:["No","Yes, regularly","Once is enough","Never"],correct:1}},{{question:"Who should be prepared?",options:["Nobody","Everyone","Only adults","Only children"],correct:1}}],icon:"✅"}},{{id:4,type:"content",title:"During Emergency",content:{during},icon:"🚨"}},{{id:5,type:"quiz",title:"Checkpoint Quiz: Response",questions:[{{question:"First action in emergency?",options:["Panic","Stay calm, follow plan","Run randomly","Ignore it"],correct:1}},{{question:"Should you help others?",options:["No","Yes, if safe to do so","Never","Always, even if dangerous"],correct:1}},{{question:"Follow official instructions?",options:["No","Yes, always","Sometimes","Never"],correct:1}},{{question:"Stay informed during emergency?",options:["No","Yes, monitor updates","Ignore news","Sleep"],correct:1}},{{question:"Can you improvise if needed?",options:["No, never","Yes, adapt to situation","Always panic","Give up"],correct:1}}],icon:"✅"}},{{id:6,type:"content",title:"After Emergency",content:{after},icon:"🏠"}},{{id:7,type:"final-quiz",title:"Final Assessment",questions:[{{question:"Is preparation important?",options:["No","Yes, saves lives","Maybe","Never"],correct:1}},{{question:"Can emergencies be survived?",options:["No","Yes, with preparation","Never","Only sometimes"],correct:1}},{{question:"Should you help community recover?",options:["No","Yes, support each other","Never","Only yourself"],correct:1}},{{question:"Learn from experience?",options:["No","Yes, improve preparedness","Never","Forget it"],correct:1}},{{question:"Stay prepared after emergency?",options:["No","Yes, maintain readiness","Only during","Never again"],correct:1}}],icon:"🏆"}}];useEffect(()=>{{const saved=JSON.parse(localStorage.getItem("{storage}")||"{{}}"if(saved.completedCheckpoints){{setCompletedCheckpoints(saved.completedCheckpoints);setCurrentCheckpoint(saved.currentCheckpoint||0);setScore(saved.score||0);}}}},[]);const saveProgress=(checkpoint,completed,newScore)=>{{localStorage.setItem("{storage}",JSON.stringify({{currentCheckpoint:checkpoint,completedCheckpoints:completed,score:newScore}}));}}const completeCheckpoint=()=>{{const newCompleted=[...completedCheckpoints,currentCheckpoint];setCompletedCheckpoints(newCompleted);if(currentCheckpoint===checkpoints.length-1){{setModuleComplete(true);saveProgress(currentCheckpoint,newCompleted,score);}}else{{const nextCheckpoint=currentCheckpoint+1;setCurrentCheckpoint(nextCheckpoint);saveProgress(nextCheckpoint,newCompleted,score);}}setQuizAnswers({{}});setQuizResult(null);}}const handleQuizAnswer=(questionIndex,answerIndex)=>{{setQuizAnswers({{...quizAnswers,[questionIndex]:answerIndex}});}}const submitQuiz=()=>{{const checkpoint=checkpoints[currentCheckpoint];let correct=0;checkpoint.questions.forEach((q,i)=>{{if(quizAnswers[i]===q.correct)correct++;}});const quizScore=(correct/checkpoint.questions.length)*100;const passed=quizScore>=80;setQuizResult({{score:quizScore,correct:correct,total:checkpoint.questions.length,passed:passed}});if(passed)setScore(score+quizScore);}}const retakeQuiz=()=>{{setQuizAnswers({{}});setQuizResult(null);}}const checkpoint=checkpoints[currentCheckpoint];const progress=((completedCheckpoints.length/checkpoints.length)*100).toFixed(0);return(<><Navbar/><div className="gamified-learning-page"><BackButton/><div className="learning-header"><div className="module-title-section"><span className="module-icon-large">{icon}</span><h1>{title} Mastery</h1></div><div className="progress-section"><div className="progress-bar-container"><div className="progress-bar"style={{{{width:`${{progress}}%`}}}}></div></div><div className="progress-stats"><span>Progress:{{progress}}%</span><span>Score:{{score.toFixed(0)}}pts</span><span>Checkpoint:{{currentCheckpoint+1}}/{{checkpoints.length}}</span></div></div></div><div className="checkpoint-map">{{checkpoints.map((cp,i)=>(<div key={{cp.id}}className={{`checkpoint-node ${{completedCheckpoints.includes(i)?'completed':''}} ${{i===currentCheckpoint?'active':''}} ${{i>currentCheckpoint?'locked':''}}`}}><span className="checkpoint-icon">{{cp.icon}}</span><span className="checkpoint-label">{{cp.title}}</span></div>))}}</div>{{moduleComplete?(<div className="completion-card"><h2>🎉 Module Complete!</h2><div className="completion-stats"><div className="stat"><span className="stat-value">{{score.toFixed(0)}}</span><span className="stat-label">Total Points</span></div><div className="stat"><span className="stat-value">{{checkpoints.length}}</span><span className="stat-label">Checkpoints</span></div><div className="stat"><span className="stat-value">🏆</span><span className="stat-label">Badge Earned</span></div></div><button className="btn-continue"onClick={{()=>navigate('/home')}}>Back to Dashboard</button></div>):(<div className="checkpoint-content"><div className="checkpoint-header"><span className="checkpoint-number">Checkpoint{{currentCheckpoint+1}}</span><h2>{{checkpoint.title}}</h2></div>{{checkpoint.type==="intro"&&(<div className="intro-content"><p>{{checkpoint.content}}</p><button className="btn-next"onClick={{completeCheckpoint}}>Start Learning →</button></div>)}}{{checkpoint.type==="video"&&(<div className="video-content"><iframe src={{checkpoint.videoUrl}}className="checkpoint-video"frameBorder="0"allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"allowFullScreen/><button className="btn-next"onClick={{completeCheckpoint}}>Continue →</button></div>)}}{{checkpoint.type==="content"&&(<div className="content-section"><ul className="content-list">{{checkpoint.content.map((item,i)=><li key={{i}}>{{item}}</li>)}}</ul><button className="btn-next"onClick={{completeCheckpoint}}>Continue →</button></div>)}}{{(checkpoint.type==="quiz"||checkpoint.type==="final-quiz")&&(<div className="quiz-section">{{!quizResult?(<>{{checkpoint.questions.map((q,qIndex)=>(<div key={{qIndex}}className="quiz-question"><h3>Question{{qIndex+1}}:{{q.question}}</h3><div className="quiz-options">{{q.options.map((option,oIndex)=>(<button key={{oIndex}}className={{`quiz-option ${{quizAnswers[qIndex]===oIndex?'selected':''}}`}}onClick={{()=>handleQuizAnswer(qIndex,oIndex)}}>{{option}}</button>))}}</div></div>))}}<button className="btn-submit"onClick={{submitQuiz}}disabled={{Object.keys(quizAnswers).length!==checkpoint.questions.length}}>Submit Quiz</button></>):(<div className="quiz-result-card"><h2>{{quizResult.passed?'🎉 Quiz Passed!':'❌ Quiz Failed'}}</h2><div className="result-score"><span className="score-large">{{quizResult.score.toFixed(0)}}%</span><span className="score-detail">{{quizResult.correct}}/{{quizResult.total}}correct</span></div><div className="question-review"><h3>Question Review:</h3>{{checkpoint.questions.map((q,qIndex)=>{{const userAnswer=quizAnswers[qIndex];const isCorrect=userAnswer===q.correct;return(<div key={{qIndex}}className={{`review-item ${{isCorrect?'correct':'incorrect'}}`}}><div className="review-header"><span className="review-icon">{{isCorrect?'✓':'✗'}}</span><span className="review-status">{{isCorrect?'Correct':'Incorrect'}}</span></div><p className="review-question">Q{{qIndex+1}}:{{q.question}}</p><p className="review-answer">Your answer:{{q.options[userAnswer]}}</p>{{!isCorrect&&<p className="review-correct">Correct answer:{{q.options[q.correct]}}</p>}}</div>);}});}}}</div><p className="result-message">{{quizResult.passed?'Great job! You can proceed to the next checkpoint.':'You need 80% to pass. Review the material and try again.'}}</p><div className="result-actions">{{quizResult.passed?(<button className="btn-next"onClick={{completeCheckpoint}}>Continue to Next Checkpoint →</button>):(<button className="btn-retake"onClick={{retakeQuiz}}>Retake Quiz</button>)}}</div></div>)}}</div>)}}</div>)}}</div></>);}}'''

for m in modules:
    code=template.format(name=m[0],title=m[1],icon=m[2],storage=m[3],video=m[4],before=str(m[5]),during=str(m[6]),after=str(m[7]))
    with open(f"{m[0]}.js","w",encoding="utf-8")as f:
        f.write(code)
    print(f"Created {m[0]}.js")
